-- в”Ђв”Ђ Admitsee в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$AdmitSee is a college admissions platform where students search real accepted-student essays and profiles, message peer mentors, and get data-driven insight into what got applicants into their target schools.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free limited access for eligible students; paid unlock packages start around 60 dollars$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Small$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AdmitSee Review: College Essay and Admissions Data Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$AdmitSee lets students search real accepted-student essays and admissions profiles. See pricing plans, features, pros and cons, and how it compares.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AdmitSee is a college admissions platform founded in 2013 by former University of Pennsylvania classmates Stephanie Shyu and Lydia Fayal, headquartered in San Francisco with a presence in New York City. The company's core product is a searchable database of real accepted-student application files, including personal statements, supplemental essays, GPA and test scores, extracurricular resumes, honors and awards, and narrative advice about the admissions process, all contributed by students who were accepted to the schools they applied to. The stated mission is to level the admissions playing field by giving high school students affordable access to the kind of insider admissions information that has traditionally been available mainly to families who could afford expensive private counseling. Beyond browsing profiles, AdmitSee lets users message the profile owners directly to ask questions about their application strategy, essay topics, and experience at a given school, effectively functioning as a peer-mentorship layer on top of the data. AdmitSee monetizes through a freemium, unlock-based membership model rather than a flat monthly subscription. A Basic plan sells a set number of profile unlocks (five for 60 dollars) with one year of access, while grade-specific annual memberships, branded by expected graduating class (for example, Class of 2027 through Class of 2030), bundle a larger number of unlocks, messaging privileges, data insights, and advanced search, priced from roughly 150 dollars up to 350 dollars depending on how many years of access and unlocks are included, with per-unlock cost decreasing at higher tiers. AdmitSee also provides free access, typically five profile unlocks, to students attending Title I schools or who qualify for free and reduced lunch programs, targeting under-resourced students directly. For school counselors, a separate Counselor Access plan offers access to 100 profiles and advanced search for a flat annual fee. Beyond the self-serve platform, AdmitSee offers a premium, high-touch advising service pairing students with admissions consultants for a fixed number of hours of one-on-one guidance, priced in the thousands of dollars, positioning the company at both the low-cost, self-serve end and the premium, white-glove end of the college admissions consulting market. AdmitSee is best understood as a data and community product for the college application research phase rather than a full application-management or essay-editing tool, and it competes with other data-driven admissions platforms as well as traditional independent educational consultants.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3e7cd212-e364-4192-be8c-cab48ff64fb4';

