  company_size = COALESCE($q$Large (part of SS&C Technologies, a global enterprise)$q$, company_size),
  headquarters = COALESCE($q$Formerly San Francisco, California; now part of SS&C Technologies, headquartered in Windsor, Connecticut$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Advent Software Review: History and SS&C Advent Today$q$, seo_title),
  seo_meta_description = COALESCE($q$Advent Software was acquired by SS&C Technologies in 2015 and now operates as SS&C Advent. See its history, products, and current status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Advent Software was an investment management software company founded in San Francisco in June 1983 by Stephanie DiMarco and Steve Strand, built to serve investment managers, hedge funds, family offices, and wealth managers with portfolio accounting, trading, compliance, and reporting technology. Advent built an early reputation on innovation in the space: in 1984 it launched one of the first PC-based portfolio accounting systems, and in 1992 it introduced Axys, an early Windows-based portfolio accounting and reporting solution that became widely used across the buy-side. The company later developed Advent Geneva, a global portfolio management and accounting platform used by hedge funds and asset managers, among other products. Advent went public on NASDAQ under the ticker ADVS and grew into one of the most established names in investment management technology over more than three decades as an independent company. On February 2, 2015, SS&C Technologies Holdings announced a definitive agreement to acquire Advent Software for an enterprise value of approximately 2.7 billion dollars in cash, equating to 44.25 dollars per share plus assumption of debt; the acquisition closed on July 8, 2015. Following the deal, the combined company became a leading global provider of investment management software and services, serving more than 10,000 customers worldwide with combined revenues of approximately 1.2 billion dollars at the time. Advent's products were rebranded as SS&C Advent, a business unit within SS&C Technologies, and continue to be sold and supported under that name today rather than as an independent company. SS&C Advent's current offerings, organized by functional category rather than legacy product names, span portfolio management, accounting and reporting, trading, rebalancing and compliance, fund order management, data management, client portals, fund accounting, investor servicing, margin and finance management, research management, client relationship management, and performance, reporting and attribution, serving more than 5,000 buy-side firms and reportedly supporting management of trillions of dollars in assets. This directory entry reflects the historical Advent Software brand; buyers evaluating this technology today should understand it as SS&C Advent, a division of SS&C Technologies headquartered in Windsor, Connecticut, sold with custom enterprise pricing rather than as a separately purchasable independent company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '03c5a767-07d3-404e-bc1f-985cc68f5cc3';

